mapper.select:
SELECT u.id, u.username, u.password, u.name, u.phone, u.role_name, r.permissions, u.enabled, u.created_at, u.updated_at, u.deleted FROM sys_user_account u LEFT JOIN sys_role r ON r.deleted = 0 AND (r.role_code = u.role_name OR r.name = u.role_name) WHERE u.deleted = 0
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR u.role_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY u.id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE sys_user_account
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
